type Cell = [number, number];

const isNeighbor = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
  (x !== otherX || y !== otherY) &&
  Math.abs(otherX - x) <= 1 &&
  Math.abs(otherY - y) <= 1;

const countLiveNeighbors = (cell: Cell, livingCells: Cell[]): number =>
  livingCells.filter((other) => isNeighbor(cell, other)).length;

const survives = (neighborCount: number): boolean =>
  neighborCount === 2 || neighborCount === 3;

const reproduces = (neighborCount: number): boolean => neighborCount === 3;

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const OFFSETS = [-1, 0, 1] as const;

const neighborsOf = ([x, y]: Cell): Cell[] =>
  OFFSETS.flatMap((dx) =>
    OFFSETS
      .filter((dy) => dx !== 0 || dy !== 0)
      .map((dy): Cell => [x + dx, y + dy]),
  );

const uniqueDeadNeighbors = (livingCells: Cell[]): Cell[] => {
  const liveKeys = new Set(livingCells.map(cellKey));
  const deadNeighbors = new Map<string, Cell>();
  for (const cell of livingCells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      if (!liveKeys.has(key)) deadNeighbors.set(key, neighbor);
    }
  }
  return [...deadNeighbors.values()];
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const hasNeighborCount = (rule: (count: number) => boolean) =>
    (cell: Cell) => rule(countLiveNeighbors(cell, cells));
  const survivors = cells.filter(hasNeighborCount(survives));
  const births = uniqueDeadNeighbors(cells).filter(hasNeighborCount(reproduces));
  return [...survivors, ...births];
}

